# prompts/loader.py (extended)
from pathlib import Path
import yaml

class LayeredPromptBuilder:
    """
    Builds a system prompt by composing a base template with
    endpoint-specific sections. The base holds identity and safety;
    extensions add capability scope and output format.
    """

    def __init__(self, base_id: str):
        self._sections = []
        base = registry.get(base_id)
        self._sections.append(base.system)

    def add_capability_section(self, text: str) -> "LayeredPromptBuilder":
        self._sections.append(text)
        return self

    def add_format_section(self, text: str) -> "LayeredPromptBuilder":
        self._sections.append(text)
        return self

    def add_context(self, tag: str, content: str) -> "LayeredPromptBuilder":
        self._sections.append(f"<acme:{tag}>\n{content}\n</acme:{tag}>")
        return self

    def build(self) -> str:
        return "\n\n".join(self._sections)


# Usage: each endpoint gets a composed prompt
def build_invoice_explain_prompt(account_data: str, invoice_data: str) -> str:
    return (
        LayeredPromptBuilder("acme-base")
        .add_capability_section(
            "You can: explain line items on invoices in the customer account.\n"
            "You cannot: issue credits, access other accounts, or discuss products."
        )
        .add_format_section(
            "Output: plain prose, 2-4 sentences, same language as the user's message."
        )
        .add_context("account", account_data)
        .add_context("invoice", invoice_data)
        .build()
    )
